import json, os, re

# Get all temporary files
tmp_dir = '/tmp'
files = os.listdir(tmp_dir)

# Identify clinical and mutation data files
clinical_file = None
mutation_file = None

for f in files:
    if not f.endswith('.json'):
        continue
    f_path = os.path.join(tmp_dir, f)
    try:
        with open(f_path, 'r', encoding='utf-8') as reader:
            content = reader.read(1000)
            if 'Patient_description' in content and 'Breast' in content:
                clinical_file = f_path
            elif 'ParticipantBarcode' in content and 'Hugo_Symbol' in content:
                mutation_file = f_path
    except:
        pass

print('Clinical file found: ', clinical_file is not None)
print('Mutation file found: ', mutation_file is not None)

if clinical_file and mutation_file:
    # Load data
    with open(clinical_file, 'r', encoding='utf-8') as f:
        clinical_records = json.load(f)

    with open(mutation_file, 'r', encoding='utf-8') as f:
        mutation_records = json.load(f)

    # Filter CDH1 mutations
    cdh1_participants = set()
    for rec in mutation_records:
        if rec.get('Hugo_Symbol') == 'CDH1':
            cdh1_participants.add(rec['ParticipantBarcode'])

    # Process BRCA alive patients
    brca_patients = []
    for rec in clinical_records:
        desc = rec.get('Patient_description', '')
        if 'Breast' in desc and 'Alive' in desc:
            match = re.search(r'TCGA-\w{2}-\w{4}', desc)
            if match:
                barcode = match.group(0)
                histo = rec.get('histological_type', 'Unknown')
                brca_patients.append({'barcode': barcode, 'histological_type': histo})

    # Calculate statistics by histological type
    histo_stats = {}
    for p in brca_patients:
        h = p['histological_type']
        if h not in histo_stats:
            histo_stats[h] = {'total': 0, 'mutated': 0}
        histo_stats[h]['total'] += 1
        if p['barcode'] in cdh1_participants:
            histo_stats[h]['mutated'] += 1

    # Calculate percentages and get top 3
    results = []
    for h, s in histo_stats.items():
        pct = round(s['mutated'] / s['total'] * 100, 2) if s['total'] > 0 else 0
        results.append({'histological_type': h, 'percentage': pct, 'total_patients': s['total'], 'mutated_patients': s['mutated']})

    results.sort(key=lambda x: x['percentage'], reverse=True)
    top3 = results[:3]

    print('Clinical records:', len(clinical_records))
    print('BRCA alive patients:', len(brca_patients))
    print('CDH1 mutation participants:', len(cdh1_participants))
    print('Histological types analyzed:', len(histo_stats))

    output = {'top_3_histological_types': top3}
else:
    output = {'error': 'Required files not found'}

# Print result in required format
print('__RESULT__:')
print(json.dumps(output))

