import json, os

# Try to access variables from previous tool calls
# These should be available as var_functions.query_db:24 and var_functions.query_db:28
# but they might be file paths rather than direct data

clinical_var_name = 'var_functions.query_db:24'
mutation_var_name = 'var_functions.query_db:28'

# Check if these variables exist in local scope
all_vars = list(locals().keys()) + list(globals().keys())
print('Available variables:')
clinical_data = None
mutation_data = None

# Try different approaches to get the data
# Approach 1: Try common variable names
for key in all_vars:
    if 'query_db' in key and ('24' in key or 'clinical' in key):
        clinical_data = locals().get(key) or globals().get(key)
        print(f'Found clinical data in {key}, type: {type(clinical_data)}')
    if 'query_db' in key and ('28' in key or 'mutation' in key):
        mutation_data = locals().get(key) or globals().get(key)
        print(f'Found mutation data in {key}, type: {type(mutation_data)}')

# Approach 2: Direct access
if clinical_data is None and clinical_var_name.replace(':', '_') in all_vars:
    clinical_data = locals().get(clinical_var_name.replace(':', '_')) or globals().get(clinical_var_name.replace(':', '_'))

if mutation_data is None and mutation_var_name.replace(':', '_') in all_vars:
    mutation_data = locals().get(mutation_var_name.replace(':', '_')) or globals().get(mutation_var_name.replace(':', '_'))

# Approach 3: Check temp files again but more carefully
print('\nChecking /tmp directory for data files:')
tmp_files = [f for f in os.listdir('/tmp') if f.endswith('.json')]
for f in tmp_files:
    f_path = f'/tmp/{f}'
    try:
        with open(f_path, 'r') as reader:
            data = json.load(reader)
            if isinstance(data, list) and len(data) > 0:
                first_record = data[0]
                if 'Patient_description' in first_record and 'Breast' in str(data):
                    clinical_data = data
                    print(f'Found clinical data in file: {f}')
                elif 'ParticipantBarcode' in first_record and 'Hugo_Symbol' in first_record:
                    mutation_data = data
                    print(f'Found mutation data in file: {f}')
    except Exception as e:
        continue

# If we found both datasets, process them
result = {'status': 'Initializing'}

if clinical_data and mutation_data:
    print(f'\nProcessing data...')
    print(f'Clinical records: {len(clinical_data)}')
    print(f'Mutation records: {len(mutation_data)}')

    import re

    # Step 1: Filter alive BRCA patients
    brca_alive = []
    for rec in clinical_data:
        desc = rec.get('Patient_description', '')
        if 'Breast' in desc and 'Alive' in desc:
            match = re.search(r'TCGA-\w{2}-\w{4}', desc)
            if match:
                brca_alive.append({
                    'barcode': match.group(0),
                    'histological_type': rec.get('histological_type', 'Unknown')
                })

    print(f'Alive breast cancer patients: {len(brca_alive)}')

    # Step 2: Get CDH1 mutation participants
    cdh1_barcodes = set()
    for rec in mutation_data:
        if rec.get('Hugo_Symbol') == 'CDH1':
            cdh1_barcodes.add(rec['ParticipantBarcode'])

    print(f'CDH1 mutations across all cancers: {len(cdh1_barcodes)}')

    # Step 3: Calculate stats by histological type
    histo_stats = {}
    for patient in brca_alive:
        h = patient['histological_type']
        if h not in histo_stats:
            histo_stats[h] = {'total': 0, 'mutated': 0}

        histo_stats[h]['total'] += 1
        if patient['barcode'] in cdh1_barcodes:
            histo_stats[h]['mutated'] += 1

    # Step 4: Calculate percentages and get top 3
    results = []
    for h, stats in histo_stats.items():
        pct = round(stats['mutated'] / stats['total'] * 100, 2) if stats['total'] > 0 else 0
        results.append({
            'histological_type': h,
            'percentage': pct,
            'total_patients': stats['total'],
            'mutated_patients': stats['mutated']
        })

    results.sort(key=lambda x: x['percentage'], reverse=True)
    top3 = results[:3]

    result = {'top_3_histological_types': top3}
